/**
 * HUDPanel — Always-visible HUD overlay for local map and world map.
 * Shows in-game time, party gold, ration points, and a compass rose.
 * Updates every second via setInterval.
 * Uses pointer-events: none so it never blocks canvas input.
 *
 * @module HUDPanel
 */

import DebugLog from '../debug/DebugLog.js';
import WorldState from '../world/WorldState.js';
import EventBus from '../core/EventBus.js';

// ─── Compass directions ───────────────────────────────────────────────────────

const COMPASS_LABELS = ['N', 'NE', 'E', 'SE', 'S', 'SW', 'W', 'NW'];

// ─── Minimap tile color palette (must stay in sync with LocalMapScene) ────────

const MINIMAP_TILE_COLORS = {
  grass:    '#4a7a2a',
  forest:   '#2a5a1a',
  mountain: '#7a6a5a',
  water:    '#1a3a5c',
  sand:     '#c8aa5a',
  snow:     '#e8e8f0',
  road:     '#8a7a5a',
};

// ─── Status effect badge config ───────────────────────────────────────────────

const STATUS_BADGES = {
  poisoned: { dot: '🟢', label: 'Poisoned' },
  burning:  { dot: '🔴', label: 'Burning'  },
  frozen:   { dot: '🔵', label: 'Frozen'   },
  stunned:  { dot: '🟡', label: 'Stunned'  },
};

// ─── Weather icons ────────────────────────────────────────────────────────────

const WEATHER_ICONS = {
  clear:    '☀️',
  cloudy:   '☁️',
  rainy:    '🌧️',
  stormy:   '⛈️',
  snow:     '🌨️',
  foggy:    '🌫️',
  hot:      '🔥',
  blizzard: '❄️',
  windy:    '💨',
  frozen:   '❄️',
};

// ─── HUDPanel ─────────────────────────────────────────────────────────────────

class HUDPanel {
  constructor() {
    /** @type {HTMLElement|null} Root HUD container */
    this._el = null;

    /** @type {number|null} setInterval ID */
    this._intervalId = null;

    /** @type {boolean} Whether the HUD is currently mounted */
    this._active = false;

    /** @type {Function|null} Reference to TimeSystem.formatTime for display */
    this._formatTime = null;

    /** @type {Function|null} Reference to TimeSystem.isNight */
    this._isNight = null;

    /** @type {number} Compass heading degrees (updated externally if desired) */
    this._heading = 0;

    /** @type {Function|null} EventBus unsubscribe for weather:changed */
    this._weatherUnsub = null;

    /** @type {Function|null} EventBus unsubscribe for local:partyMoved */
    this._movedUnsub = null;

    /** @type {Function|null} EventBus unsubscribe for localmap:built */
    this._builtUnsub = null;

    /** @type {Function|null} EventBus unsubscribe for party:hpChanged */
    this._hpUnsub = null;

    /** @type {Function|null} EventBus unsubscribe for combat:stateChanged */
    this._combatStateUnsub = null;

    /** @type {Function|null} EventBus unsubscribe for party:goldChanged */
    this._goldUnsub = null;

    /** @type {boolean} Whether the HUD minimap is currently visible */
    this._minimapVisible = true;

    /** @type {Function|null} keydown listener for M-key minimap toggle */
    this._minimapKeyFn = null;
  }

  // ─── Public API ──────────────────────────────────────────────────────────────

  /**
   * Mount and start the HUD.
   * Safe to call multiple times — destroys previous instance first.
   *
   * @param {object} [options]
   * @param {Function} [options.formatTime] — Override TimeSystem.formatTime
   * @param {Function} [options.isNight] — Override TimeSystem.isNight
   */
  init(options = {}) {
    // Destroy any existing HUD
    this.destroy();

    this._formatTime = options.formatTime ?? this._getTimeFn('formatTime');
    this._isNight    = options.isNight    ?? this._getTimeFn('isNight');

    this._buildDOM();
    this.update();

    // Refresh every 1 second
    this._intervalId = setInterval(() => this.update(), 1000);
    this._active = true;

    // Subscribe to weather changes so the weather indicator updates immediately
    this._weatherUnsub = EventBus.on('weather:changed', (data) => {
      this._updateWeatherDisplay(data);
    });

    // Minimap: update on party movement and map build events
    this._movedUnsub = EventBus.on('local:partyMoved', () => {
      this._drawHUDMinimap();
    });
    this._builtUnsub = EventBus.on('localmap:built', () => {
      this._drawHUDMinimap();
    });

    // HP bars and status effects
    this._hpUnsub = EventBus.on('party:hpChanged', () => {
      this._updatePartyCards();
    });
    this._combatStateUnsub = EventBus.on('combat:stateChanged', () => {
      this._updatePartyCards();
    });

    // Gold animation
    this._goldUnsub = EventBus.on('party:goldChanged', () => {
      this._animateGold();
    });

    // Load minimap visibility preference
    const stored = localStorage.getItem('hud_minimap_visible');
    this._minimapVisible = stored === null ? true : stored === 'true';

    // M-key toggles minimap visibility
    this._minimapKeyFn = (e) => {
      if (e.key === 'm' || e.key === 'M') {
        this._toggleMinimap();
      }
    };
    window.addEventListener('keydown', this._minimapKeyFn);

    // Populate weather indicator from current WeatherSystem state (if available)
    this._syncWeatherDisplay();

    // Draw minimap immediately if local map data is available
    this._drawHUDMinimap();

    // Initial party cards
    this._updatePartyCards();

    // Apply initial minimap visibility
    this._applyMinimapVisibility();

    DebugLog.info('[debug] HUDPanel initialized');
  }

  /**
   * Force-refresh the displayed values.
   * Called automatically by the interval, but can also be called externally
   * after a state change (e.g., gold changes after a purchase).
   */
  update() {
    if (!this._el) return;

    const timeEl   = this._el.querySelector('#hud-time');
    const goldEl   = this._el.querySelector('#hud-gold');
    const rationsEl = this._el.querySelector('#hud-rations');
    const nightEl  = this._el.querySelector('#hud-night-indicator');

    const timeStr = this._getFormattedTime();
    const isNight = this._checkIsNight();
    const gold    = WorldState.partyGold ?? 0;
    const rations = WorldState.rationPoints ?? 0;

    if (timeEl)    timeEl.textContent = timeStr;
    if (goldEl)    goldEl.textContent = `${gold}g`;
    if (rationsEl) {
      rationsEl.textContent = `${rations} rations`;
      rationsEl.classList.toggle('hud-rations-low', rations <= 5);
    }

    // Night indicator — subtle pulse when night
    if (nightEl) {
      nightEl.style.display = isNight ? 'inline-block' : 'none';
    }

    // Update night dimness class on body for scene-level darkness
    document.body.classList.toggle('hud-night-mode', isNight);
  }

  /**
   * Remove the HUD from the DOM and stop the update loop.
   */
  destroy() {
    if (this._intervalId != null) {
      clearInterval(this._intervalId);
      this._intervalId = null;
    }

    if (this._weatherUnsub) {
      this._weatherUnsub();
      this._weatherUnsub = null;
    }

    if (this._movedUnsub) {
      this._movedUnsub();
      this._movedUnsub = null;
    }

    if (this._builtUnsub) {
      this._builtUnsub();
      this._builtUnsub = null;
    }

    if (this._hpUnsub) {
      this._hpUnsub();
      this._hpUnsub = null;
    }

    if (this._combatStateUnsub) {
      this._combatStateUnsub();
      this._combatStateUnsub = null;
    }

    if (this._goldUnsub) {
      this._goldUnsub();
      this._goldUnsub = null;
    }

    if (this._minimapKeyFn) {
      window.removeEventListener('keydown', this._minimapKeyFn);
      this._minimapKeyFn = null;
    }

    if (this._el) {
      this._el.remove();
      this._el = null;
    }

    document.body.classList.remove('hud-night-mode');

    this._active = false;
    DebugLog.info('[debug] HUDPanel destroyed');
  }

  /**
   * Update the compass heading (optional — call from camera/movement system).
   * @param {number} degrees — 0 = North, 90 = East, etc.
   */
  setHeading(degrees) {
    this._heading = degrees % 360;
    const compassNeedle = this._el?.querySelector('.hud-compass-needle');
    if (compassNeedle) {
      compassNeedle.style.transform = `rotate(${this._heading}deg)`;
    }
  }

  // ─── Weather helpers ─────────────────────────────────────────────────────────

  /**
   * Sync the weather display from the current WeatherSystem state (if loaded).
   * Called once during init so the indicator shows correct data immediately.
   */
  _syncWeatherDisplay() {
    try {
      const ws = window.__weatherSystem;
      if (ws) {
        this._updateWeatherDisplay(ws.getCurrentWeather());
      }
    } catch (_) {}
  }

  /**
   * Update the #hud-weather element with data from a weather:changed event.
   * @param {{ season: string, weather: string }} data
   */
  _updateWeatherDisplay(data) {
    const el = this._el?.querySelector('#hud-weather');
    if (!el || !data) return;

    const icon = WEATHER_ICONS[data.weather] ?? '☀️';
    const cap  = (s) => s ? s.charAt(0).toUpperCase() + s.slice(1) : '';
    el.textContent = `${icon} ${cap(data.season)}`;
  }

  // ─── DOM construction ────────────────────────────────────────────────────────

  _buildDOM() {
    // Remove any stale instance
    document.getElementById('hud-panel-root')?.remove();

    const el = document.createElement('div');
    el.id = 'hud-panel-root';
    el.setAttribute('aria-hidden', 'true'); // HUD is decorative, not interactive
    el.innerHTML = `
      <div id="hud-top-bar">

        <!-- Top-left: in-game time -->
        <div id="hud-top-left" class="hud-block hud-time-block">
          <span class="hud-label">Time</span>
          <span id="hud-time" class="hud-value">--:--</span>
          <span id="hud-night-indicator" class="hud-night-star" style="display:none;" title="Night">&#9733;</span>
        </div>

        <!-- Top-center: compass rose -->
        <div id="hud-top-center" class="hud-block hud-compass-block">
          <div class="hud-compass" title="Compass">
            <svg class="hud-compass-svg" viewBox="0 0 40 40" width="36" height="36"
                 aria-hidden="true" focusable="false">
              <!-- Compass ring -->
              <circle cx="20" cy="20" r="18" fill="none" stroke="#5a4a20" stroke-width="1"/>
              <!-- Cardinal tick marks -->
              <line x1="20" y1="3"  x2="20" y2="8"  stroke="#7a6a40" stroke-width="1.5"/>
              <line x1="20" y1="32" x2="20" y2="37" stroke="#5a4a30" stroke-width="1"/>
              <line x1="3"  y1="20" x2="8"  y2="20" stroke="#5a4a30" stroke-width="1"/>
              <line x1="32" y1="20" x2="37" y2="20" stroke="#5a4a30" stroke-width="1"/>
              <!-- N label -->
              <text x="20" y="14" text-anchor="middle" dominant-baseline="middle"
                    font-family="Georgia,serif" font-size="7" fill="#c8a020" font-weight="bold">N</text>
              <!-- Needle (rotated by heading via style) -->
              <g class="hud-compass-needle" style="transform-origin:20px 20px; transform:rotate(0deg)">
                <!-- North pointer (gold) -->
                <polygon points="20,6 17,20 20,18 23,20" fill="#c8a020" opacity="0.9"/>
                <!-- South pointer (dark) -->
                <polygon points="20,34 17,20 20,22 23,20" fill="#3a2a10" opacity="0.7"/>
              </g>
            </svg>
          </div>
        </div>

        <!-- Top-right: gold + rations -->
        <div id="hud-top-right" class="hud-block hud-resources-block">
          <div class="hud-resource-row">
            <span class="hud-resource-icon hud-icon-gold">&#9670;</span>
            <span id="hud-gold" class="hud-value hud-value--gold">0g</span>
          </div>
          <div class="hud-resource-row">
            <span class="hud-resource-icon hud-icon-rations">&#9670;</span>
            <span id="hud-rations" class="hud-value hud-value--rations">0 rations</span>
          </div>
          <div class="hud-resource-row">
            <div id="hud-weather" class="hud-weather">&#9728; Spring</div>
          </div>
        </div>

      </div>

      <!-- Bottom-left: party HP cards -->
      <div id="hud-party-bar"></div>

      <!-- Bottom-right: minimap canvas -->
      <div id="hud-minimap-wrap">
        <canvas id="hud-minimap" aria-label="Minimap"></canvas>
      </div>
    `;

    Object.assign(el.style, {
      position:      'fixed',
      inset:         '0',
      zIndex:        'var(--z-hud, 100)',
      pointerEvents: 'none',
      fontFamily:    "'Georgia', 'Times New Roman', serif",
    });

    document.body.appendChild(el);
    this._el = el;

    // Inject HUD styles once
    if (!document.getElementById('hud-panel-styles')) {
      const style = document.createElement('style');
      style.id = 'hud-panel-styles';
      style.textContent = HUD_STYLES;
      document.head.appendChild(style);
    }
  }

  // ─── Minimap ─────────────────────────────────────────────────────────────────

  /**
   * Toggle HUD minimap visibility. Persists preference to localStorage.
   */
  _toggleMinimap() {
    this._minimapVisible = !this._minimapVisible;
    localStorage.setItem('hud_minimap_visible', String(this._minimapVisible));
    this._applyMinimapVisibility();
  }

  _applyMinimapVisibility() {
    const wrap = this._el?.querySelector('#hud-minimap-wrap');
    if (wrap) wrap.style.display = this._minimapVisible ? 'block' : 'none';
  }

  /**
   * Draw the HUD minimap canvas from current WorldState fog and tile data.
   * Uses 2D canvas with HiDPI support.
   */
  _drawHUDMinimap() {
    const canvas = this._el?.querySelector('#hud-minimap');
    if (!canvas) return;

    const isMobile = window.innerWidth < 768;
    const cssSize = isMobile ? 60 : 80;
    const dpr = window.devicePixelRatio ?? 1;

    // Resize canvas if needed
    if (canvas.style.width !== `${cssSize}px`) {
      canvas.style.width  = `${cssSize}px`;
      canvas.style.height = `${cssSize}px`;
      canvas.width  = Math.round(cssSize * dpr);
      canvas.height = Math.round(cssSize * dpr);
    }

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const w = canvas.width;
    const h = canvas.height;
    ctx.clearRect(0, 0, w, h);

    // Dark background
    ctx.fillStyle = '#000000';
    ctx.fillRect(0, 0, w, h);

    // Try to get tile data from the cached local map
    const regionId = WorldState.currentRegionId;
    if (regionId === null) return;

    const localMap = WorldState.getLocalMap(regionId);
    if (!localMap || !localMap.tiles) return;

    const { tiles, gridW, gridH } = localMap;
    const scaleX = w / gridW;
    const scaleY = h / gridH;

    for (const tile of tiles) {
      const fogState = WorldState.getFogAt(regionId, tile.x, tile.y);
      const px = tile.x * scaleX;
      const py = tile.y * scaleY;
      const pw = Math.ceil(scaleX);
      const ph = Math.ceil(scaleY);

      if (fogState === 0) {
        // Unknown — dark gray
        ctx.fillStyle = '#222222';
      } else if (fogState === 1) {
        // Semi-explored — medium gray tinted with biome color
        ctx.fillStyle = '#555555';
      } else {
        // Fully revealed — biome color
        ctx.fillStyle = MINIMAP_TILE_COLORS[tile.type] ?? '#444444';
      }

      ctx.fillRect(px, py, pw, ph);
    }

    // Party position dot (white)
    const partyX = WorldState.partyPosition.x;
    const partyY = WorldState.partyPosition.y;
    const dotX = partyX * scaleX + scaleX / 2;
    const dotY = partyY * scaleY + scaleY / 2;
    const dotR = Math.max(1.5, Math.min(scaleX, scaleY) * 0.7);

    ctx.beginPath();
    ctx.arc(dotX, dotY, dotR, 0, Math.PI * 2);
    ctx.fillStyle = '#ffffff';
    ctx.fill();
  }

  // ─── Party HP cards ───────────────────────────────────────────────────────────

  /**
   * Rebuild or refresh the party HP bar cards in #hud-party-bar.
   */
  _updatePartyCards() {
    const bar = this._el?.querySelector('#hud-party-bar');
    if (!bar) return;

    // Collect party characters from CharacterSystem or __partyState
    const chars = this._getPartyChars();
    if (!chars || chars.length === 0) {
      bar.innerHTML = '';
      return;
    }

    // Only show living characters
    const living = chars.filter(c => (c.hp ?? 0) > 0);
    if (living.length === 0) {
      bar.innerHTML = '';
      return;
    }

    bar.innerHTML = living.map(char => {
      const hp    = char.hp    ?? 0;
      const maxHP = char.maxHP ?? 1;
      const pct   = Math.max(0, Math.min(100, (hp / maxHP) * 100));

      // HP bar color: green → yellow → red
      let barColor;
      if (pct > 60)      barColor = '#4caf50';
      else if (pct > 30) barColor = '#ffb300';
      else               barColor = '#e53935';

      // Status badge icons
      const statusEffects = char.statusEffects ?? [];
      const badges = statusEffects
        .map(s => STATUS_BADGES[s]?.dot ?? '')
        .filter(Boolean)
        .join('');

      const shortName = (char.name ?? 'Hero').split(' ')[0];

      return `
        <div class="hud-party-card">
          <div class="hud-party-name">${shortName}${badges ? ` <span class="hud-status-badges">${badges}</span>` : ''}</div>
          <div class="hud-hp-bar-track">
            <div class="hud-hp-bar-fill" style="width:${pct.toFixed(1)}%; background:${barColor};"></div>
          </div>
          <div class="hud-hp-text">${hp}/${maxHP}</div>
        </div>
      `;
    }).join('');
  }

  /**
   * Retrieve party characters from available global sources.
   * @returns {object[]}
   */
  _getPartyChars() {
    try {
      const CS = window.__characterSystem;
      if (CS?.getAll) {
        const all = CS.getAll();
        if (all && all.length > 0) {
          return all.filter(c => c.isHero).slice(0, 4);
        }
      }
    } catch (_) {}

    try {
      const partyState = window.__partyState;
      if (partyState?.characters && partyState.characters.length > 0) {
        return partyState.characters;
      }
    } catch (_) {}

    return [];
  }

  // ─── Gold animation ───────────────────────────────────────────────────────────

  /**
   * Animate gold counter with a brief scale pulse.
   */
  _animateGold() {
    const goldEl = this._el?.querySelector('#hud-gold');
    if (!goldEl) return;

    // Update value immediately
    const gold = WorldState.partyGold ?? 0;
    goldEl.textContent = `${gold}g`;

    // Pulse animation
    goldEl.classList.remove('hud-gold-pulse');
    // Force reflow so the animation re-triggers
    void goldEl.offsetWidth;
    goldEl.classList.add('hud-gold-pulse');
  }

  // ─── Time helpers ────────────────────────────────────────────────────────────

  _getFormattedTime() {
    if (this._formatTime) {
      try {
        return this._formatTime();
      } catch (e) {
        DebugLog.warn(`[debug] HUDPanel.formatTime error: ${e.message}`);
      }
    }

    // Try global TimeSystem
    try {
      if (window.__timeSystem?.formatTime) {
        return window.__timeSystem.formatTime();
      }
    } catch (_) {}

    return '06:00';
  }

  _checkIsNight() {
    if (this._isNight) {
      try {
        return this._isNight();
      } catch (_) {}
    }

    try {
      if (window.__timeSystem?.isNight) {
        return window.__timeSystem.isNight();
      }
    } catch (_) {}

    return false;
  }

  /**
   * Try to resolve a method from the global TimeSystem by name.
   * @param {string} methodName
   * @returns {Function|null}
   */
  _getTimeFn(methodName) {
    try {
      if (window.__timeSystem?.[methodName]) {
        return window.__timeSystem[methodName].bind(window.__timeSystem);
      }
    } catch (_) {}
    return null;
  }
}

// ─── Component CSS ────────────────────────────────────────────────────────────

const HUD_STYLES = `
/* ── HUD Panel ──────────────────────────────────────────────────────────── */

#hud-panel-root {
  pointer-events: none;
  user-select: none;
}

#hud-top-bar {
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  padding: 8px 12px;
  pointer-events: none;
}

.hud-block {
  background: rgba(10, 7, 3, 0.68);
  border: 1px solid rgba(90, 74, 32, 0.55);
  border-radius: 4px;
  padding: 5px 10px;
  display: flex;
  align-items: center;
  gap: 5px;
  backdrop-filter: blur(2px);
}

/* Time block — explicit flex-shrink: 0 so it never loses its left anchor */
.hud-time-block {
  flex-direction: row;
  gap: 6px;
  flex-shrink: 0;
}

.hud-label {
  font-size: 9px;
  text-transform: uppercase;
  letter-spacing: 0.12em;
  color: #5a4a28;
  flex-shrink: 0;
}

.hud-value {
  font-size: clamp(11px, 1.2vw, 13px);
  color: #d0b870;
  font-weight: bold;
  letter-spacing: 0.04em;
  white-space: nowrap;
}

.hud-night-star {
  color: #6880c0;
  font-size: 10px;
  animation: hud-night-pulse 2.5s ease-in-out infinite;
}

@keyframes hud-night-pulse {
  0%,100% { opacity: 0.6; }
  50%      { opacity: 1.0; }
}

/* Compass */
.hud-compass-block {
  background: rgba(10, 7, 3, 0.65);
  padding: 4px 6px;
}

.hud-compass {
  display: flex;
  align-items: center;
  justify-content: center;
}

.hud-compass-svg {
  display: block;
}

.hud-compass-needle {
  transform-origin: 20px 20px;
  transition: transform 0.3s ease-out;
}

/* Resources block — right-side offset so it never overlaps nav/info buttons
   that world map places in the top-right corner. The margin-right pushes the
   block away from the viewport edge, clearing any 180-220px wide overlay. */
.hud-resources-block {
  flex-direction: column;
  align-items: flex-end;
  gap: 3px;
  padding: 5px 10px;
  margin-right: clamp(0px, 14vw, 200px);
}

.hud-resource-row {
  display: flex;
  align-items: center;
  gap: 5px;
}

.hud-resource-icon {
  font-size: 8px;
  opacity: 0.5;
}

.hud-icon-gold {
  color: #c8a020;
}

.hud-icon-rations {
  color: #7a9a4a;
}

.hud-value--gold {
  color: #d4aa40;
}

.hud-value--rations {
  color: #90b060;
  font-size: clamp(10px, 1.1vw, 12px);
}

/* Weather indicator — small text beneath rations */
.hud-weather {
  font-size: clamp(10px, 1.5vw, 13px);
  color: #b0c8e0;
  letter-spacing: 0.03em;
  white-space: nowrap;
  opacity: 0.9;
}

/* Night mode — map darkness overlay */
body.hud-night-mode #game-canvas {
  filter: brightness(0.70) saturate(0.75);
  transition: filter 2s ease;
}

body:not(.hud-night-mode) #game-canvas {
  filter: brightness(1.0) saturate(1.0);
  transition: filter 2s ease;
}

/* ── Minimap ──────────────────────────────────────────────────────────────── */

#hud-minimap-wrap {
  position: absolute;
  bottom: 12px;
  left: 12px;
  border: 1px solid rgba(90, 74, 32, 0.7);
  border-radius: 3px;
  background: rgba(0, 0, 0, 0.5);
  line-height: 0;
  transition: opacity 0.2s;
}

#hud-minimap {
  display: block;
  width: 80px;
  height: 80px;
  image-rendering: pixelated;
  image-rendering: crisp-edges;
}

/* ── Party HP cards ──────────────────────────────────────────────────────── */

#hud-party-bar {
  position: absolute;
  bottom: 12px;
  right: 12px;
  display: flex;
  flex-direction: column;
  gap: 4px;
  align-items: flex-end;
}

.hud-party-card {
  background: rgba(10, 7, 3, 0.72);
  border: 1px solid rgba(90, 74, 32, 0.5);
  border-radius: 3px;
  padding: 3px 6px;
  min-width: 90px;
  max-width: 110px;
}

.hud-party-name {
  font-size: clamp(9px, 1vw, 11px);
  color: #d0b870;
  font-weight: bold;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  margin-bottom: 2px;
}

.hud-status-badges {
  font-size: 9px;
  letter-spacing: 1px;
}

.hud-hp-bar-track {
  width: 100%;
  height: 4px;
  background: rgba(255, 255, 255, 0.12);
  border-radius: 2px;
  overflow: hidden;
  margin-bottom: 2px;
}

.hud-hp-bar-fill {
  height: 100%;
  border-radius: 2px;
  transition: width 0.3s ease, background 0.3s ease;
}

.hud-hp-text {
  font-size: 9px;
  color: #a09070;
  text-align: right;
}

/* ── Gold pulse animation ────────────────────────────────────────────────── */

@keyframes hud-gold-pulse {
  0%   { transform: scale(1.0); }
  40%  { transform: scale(1.2); }
  100% { transform: scale(1.0); }
}

.hud-gold-pulse {
  animation: hud-gold-pulse 0.35s ease-out;
}

/* ── Rations low warning ─────────────────────────────────────────────────── */

@keyframes pulse {
  0%, 100% { opacity: 1.0; }
  50%       { opacity: 0.5; }
}

.hud-rations-low {
  color: #ff6b35 !important;
  animation: pulse 1s infinite;
}

/* ── Responsive: hide less-essential elements on small screens ─────────── */

@media (max-width: 767px) {
  #hud-top-bar { padding: 5px 8px; }

  .hud-block { padding: 4px 7px; }

  /* Hide rations text on very small screens, keep gold */
  .hud-value--rations { display: none; }

  /* Shrink compass on mobile */
  .hud-compass-svg { width: 28px; height: 28px; }

  /* Smaller minimap on mobile */
  #hud-minimap,
  #hud-minimap-wrap #hud-minimap { width: 60px; height: 60px; }

  .hud-party-card { min-width: 72px; }
}

@media (max-width: 480px) {
  /* Hide compass on smallest screens */
  .hud-compass-block { display: none; }
}
`;

// ─── Singleton export ─────────────────────────────────────────────────────────

export default new HUDPanel();
